def word_to_phonemes(word: str, mode: str = "standard") -> list:
    """
    Chuyển từ tiếng Anh sang chuỗi âm vị đại diện.

    Args:
        word: Từ tiếng Anh
        mode: 'standard' | 'vietlish'

    Returns:
        Danh sách âm vị
    """
    word = word.lower().strip()
    if mode == "vietlish":
        if word in VIETLISH_MAP:
            _, phonemes = VIETLISH_MAP[word]
            return phonemes
        else:
            return [SPECIAL_TOKENS["UNK"]]
    else:
        # Simplified IPA mapping cho demo
        return _simple_ipa(word)


def _simple_ipa(word: str) -> list:
    """Ánh xạ IPA đơn giản hóa cho demo (không dùng g2p library)."""
    mapping = {
        "message": ["m","e","-4","s",SPECIAL_TOKENS["LINK"],"i","dʒ"],
        "inbox":   ["ɪ","n",SPECIAL_TOKENS["EN_SEP"],"b","ɒ","k","s"],
        "coffee":  ["k","ɒ","f",SPECIAL_TOKENS["EN_SEP"],"i"],
        "laptop":  ["l","æ","p",SPECIAL_TOKENS["EN_SEP"],"t","ɒ","p"],
        "email":   ["iː",SPECIAL_TOKENS["EN_SEP"],"m","eɪ","l"],
        "meeting": ["m","iː",SPECIAL_TOKENS["EN_SEP"],"t","ɪ","ŋ"],
    }
    return mapping.get(word, list(word))


if __name__ == "__main__":
    print(f"Vocabulary size: {VOCAB_SIZE}")
    print(f"\nSample vocab entries:")
    for i, (tok, idx) in enumerate(list(VOCAB.items())[:15]):
        print(f"  [{idx:3d}] {tok}")

    print(f"\n--- Vietlish conversion ---")
    for word in ["message", "inbox", "coffee", "email"]:
        ph = word_to_phonemes(word, mode="vietlish")
        print(f"  {word:12s} → {ph}")

    print(f"\n--- Standard IPA ---")
    for word in ["message", "inbox", "email"]:
        ph = word_to_phonemes(word, mode="standard")
        print(f"  {word:12s} → {ph}")
